// UPSTREAM-EVENT-NOT-TRIGGER pattern:
// A node that depends on a prior node's output triggers on the prior node's EMISSION EVENT
// — NOT on the original flow trigger.

// WRONG: A3 triggers on QuestionnaireCompleted
// → A3 runs before A1 completes
// → reads absent profile, produces empty curriculum
// → SILENT_FAILURE: no error, empty learning program, FLOW-05 enrollment silently skipped

// CORRECT: A3 triggers on BusinessProfileCreated (A1's emission)
@EventPattern('BusinessProfileCreated')  // ← NOT 'QuestionnaireCompleted'
async handleBusinessProfileCreated(event: BusinessProfileCreatedEvent) {
  // A1's structured output is available — safe to read skills[], goals[], challenges[]
  const profile = await this.db.searchDocuments(BUSINESS_PROFILES_INDEX, {
    profileId: event.profileId,
  });
  // Generate curriculum from structured skill gaps (not raw answers)
  return this.generateLearningProgram(profile.data[0]);
}
